const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
if (!body.submission_id) return { json: { _empty: true, status: 400, error: 'submission_id required' } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
const body = $('Extract').first().json.body;
return { json: { _ok: true, submission_id: body.submission_id, override_pct: body.override_pct || null, client_id: row.client_id } };

const subs = $input.item.json;
const submission = Array.isArray(subs) ? subs[0] : subs;
if (!submission) return { json: { _missing: true, status: 404, error: 'submission not found' } };
return { json: { _ok: true, submission: submission, override_pct: $('Check Admin').first().json.override_pct } };

const carriers = $input.item.json;
const carrier = Array.isArray(carriers) ? carriers[0] : carriers;
const submission = $('Submission OK').first().json.submission;
const override = $('Submission OK').first().json.override_pct;
if (!carrier) return { json: { _missing: true, status: 404, error: 'carrier not found' } };
const pct = override !== null ? parseFloat(override) : parseFloat(carrier.expected_commission_pct || 0);
if (pct <= 0) return { json: { _bad: true, status: 422, error: 'carrier has no expected_commission_pct configured; provide override_pct in the request' } };
const premium = parseInt(submission.annual_premium_cents) || 0;
if (premium <= 0) return { json: { _bad: true, status: 422, error: 'submission has no annual_premium_cents; set premium before calculating commission' } };
// First-year factor: life products get a fraction of first-year premium converted at high commission rate (Canadian convention varies wildly by carrier; this is a best-guess default). P&C is flat.
const lifeProducts = ['term_life','whole_life','universal_life','term-to-100','critical_illness','disability'];
const isLife = lifeProducts.indexOf(submission.product_line) >= 0;
const firstYearFactor = isLife ? 1.0 : 1.0;  // default 1.0; carrier-specific tuning via override_pct
const expected = Math.round(premium * (pct / 100) * firstYearFactor);
return { json: { _ok: true, row: {
  client_id: submission.client_id,
  carrier_id: carrier.id,
  submission_id: submission.id,
  commission_type: 'first_year',
  commission_year: 1,
  expected_amount_cents: expected,
  expected_at: new Date(Date.now() + 90 * 86400000).toISOString().slice(0,10),  // expect payment within 90 days of issuance
  status: 'expected',
  notes: 'Calculated: ' + premium + ' premium × ' + pct + '% commission' + (override !== null ? ' (override)' : '') + (isLife ? ', life first-year factor 1.0' : ', P&C flat')
}, computed: { premium_cents: premium, commission_pct: pct, expected_cents: expected, carrier_name: carrier.carrier_name } } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
const computed = $('Compute').first().json.computed;
return { json: { ok: true, commission: row, computed: computed } };
